"""HLD Key Technologies: Redis, Elasticsearch, Kafka — 20 deep MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def redis_lesson() -> Lesson:
    return Lesson(id="hld-redis", number=116, title="Redis",
        focus=("data structures","persistence","clustering","pub/sub","Lua scripts","eviction"),
        overview="Redis is the Swiss-army knife of system design. Know its data structures, persistence, and clustering internals.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("redis-1","What is Redis' threading model?","hard",("redis",),("Thread pool","Multi-threaded","Multi-process","Single-threaded event loop for commands; avoids locking overhead. I/O threads added in 6.0"),3,"Single-threaded means no locks, no context switches. In-memory ops are so fast one thread saturates network."),
        quiz("redis-2","What are the main Redis data structures?","medium",("redis",),("Strings, Hashes, Lists, Sets, Sorted Sets, Streams, HyperLogLog, Bitmaps","Only key-value","Tables and rows","Only strings"),0,"Each structure has specialized commands and use cases. Sorted Sets for leaderboards, Streams for event logs."),
        quiz("redis-3","What is a Redis Sorted Set and when would you use it?","hard",("redis",),("A set where each member has a score, supporting O(log n) ranked queries — ideal for leaderboards","A queue","A linked list","A hash table"),0,"ZADD/ZRANGE/ZRANK: perfect for leaderboards, priority queues, time-windowed aggregations."),
        quiz("redis-4","What is the difference between RDB and AOF persistence?","hard",("redis",),("AOF is faster","RDB is newer","No difference","RDB: periodic point-in-time snapshots. AOF: append-every-write log. RDB is compact; AOF is more durable"),3,"Best practice: use both. AOF for durability (fsync every second). RDB for fast restarts."),
        quiz("redis-5","How does Redis Cluster shard data?","hard",("redis",),("16384 hash slots distributed across master nodes; each key maps to CRC16(key) mod 16384","Range-based","Modulo N","Consistent hashing"),0,"Clients compute the slot and connect directly to the owning node. MOVED/ASK redirects handle migrations."),
        quiz("redis-6","What is Redis pub/sub and its limitation?","medium",("redis",),("A database feature","Persists all messages","Fire-and-forget messaging; messages are lost if no subscriber is listening at the time","Guarantees delivery"),2,"Pub/sub doesn't persist. For durability, use Redis Streams (XADD/XREAD with consumer groups)."),
        quiz("redis-7","What is Redis Streams vs pub/sub?","hard",("redis",),("Same thing","Streams are slower","Pub/sub is persistent","Streams persist messages, support consumer groups with acknowledgment; pub/sub is fire-and-forget"),3,"Streams (XADD/XREAD/XACK) provide Kafka-like semantics within Redis."),
        quiz("redis-8","What is the Redis eviction policy LRU vs LFU?","hard",("redis",),("LFU uses less memory","Same thing","volatile-lru: evict least recently used keys with TTL. allkeys-lfu: evict least frequently used from all keys","LRU is always better"),2,"Choose based on access pattern. LFU is better for skewed workloads where some keys are always hot."),
        quiz("redis-9","What is Redis Sentinel?","hard",("redis",),("Provides high availability with automatic failover: monitors masters, detects failure, promotes replicas","A monitoring tool only","A sharding mechanism","A data structure"),0,"Sentinel: quorum-based failure detection → automatic promotion → client notification of new master."),
        quiz("redis-10","What is the Redis MULTI/EXEC transaction?","hard",("redis",),("Same as SQL transactions","A replication feature","A locking mechanism","Queues commands and executes atomically — but no rollback on individual command failure"),3,"MULTI/EXEC: all-or-nothing execution. WATCH enables optimistic locking (CAS pattern)."),
        quiz("redis-11","What is Redis Lua scripting?","hard",("redis",),("A replication protocol","A backup feature","Execute Lua scripts atomically on the server — enables complex operations without round trips","A query language"),2,"EVAL: server-side atomic execution. Useful for rate limiting, token bucket, and complex CAS operations."),
        quiz("redis-12","What is the Redis HyperLogLog?","hard",("redis",),("A probabilistic data structure for cardinality estimation (count unique items) with O(1) space","A hash function","An eviction policy","A sorting algorithm"),0,"PFADD/PFCOUNT: count unique visitors with only 12KB memory, ~0.81% standard error."),
        quiz("redis-13","How does Redis replication work?","hard",("redis",),("Master-master","Synchronous always","Consensus-based","Async replication from master to replicas. Initial full sync (RDB dump) then incremental command stream"),3,"Async replication means replicas may lag. For strong consistency, use WAIT command."),
        quiz("redis-14","What is Redis pipelining?","medium",("redis",),("A load balancing technique","A replication feature","A persistence mode","Sending multiple commands without waiting for replies, then reading all replies — reduces round-trip overhead"),3,"Pipelining: send 1000 commands → get 1000 replies in one round trip. 10x throughput improvement."),
        quiz("redis-15","What is the Redis Bitmap data structure?","hard",("redis",),("A compact bit array supporting SETBIT/GETBIT/BITCOUNT — perfect for tracking binary states per user","A sorted set","An image format","A hash table"),0,"Bitmap: track 1B users' daily login with only 125MB. BITCOUNT for analytics. BITOP for set operations."),
        quiz("redis-16","What are the risks of using Redis as a primary database?","hard",("redis",),("Data loss if persistence isn't configured properly; limited by RAM size; no complex queries/JOINs","No risks","Redis can't persist","Redis is always reliable"),0,"Redis works as a primary DB for specific use cases (sessions, caches) but not for general transactional data."),
        quiz("redis-17","What is Redis Cluster's split-brain handling?","hard",("redis",),("Both partitions write","No split-brain possible","Minority partition nodes stop accepting writes after a timeout; clients reconnect to majority partition","Ignore it"),2,"cluster-node-timeout: nodes in minority partition become read-only. Prevents conflicting writes."),
        quiz("redis-18","How do you implement a distributed lock with Redis?","hard",("redis",),("SETNX + DELETE","SET key value NX PX milliseconds (atomic acquire with TTL); DEL to release. Redlock for multi-node","MULTI/EXEC only","INCR/DECR"),1,"SET NX PX: atomic acquire. TTL prevents deadlocks. Check lock value before releasing to prevent stale releases."),
        quiz("redis-19","What is Redis Cluster resharding?","hard",("redis",),("Add new cluster","Moving hash slots between nodes online — MIGRATE command moves keys slot by slot while serving traffic","Deleting data","Restart cluster"),1,"redis-cli --cluster reshard: moves slots live. ASK redirects handle in-flight migrations."),
        quiz("redis-20","What is the memory overhead per key in Redis?","hard",("redis",),("0 bytes","1 KB","~50-70 bytes per key for internal structures (dict entry, SDS string, expiry) regardless of value size","1 byte"),2,"With 1B small keys, overhead alone = ~50-70GB. Use hash packing for small values to reduce overhead."),
    ))

def elasticsearch_lesson() -> Lesson:
    return Lesson(id="hld-elasticsearch", number=117, title="Elasticsearch",
        focus=("inverted index","sharding","relevance scoring","aggregations","ELK stack","mapping"),
        overview="Elasticsearch powers search, analytics, and logging. Know its internals and query capabilities.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("es-1","What is Elasticsearch optimized for?","medium",("elasticsearch",),("Graph traversal","Time-series only","ACID transactions","Full-text search, analytics, and log aggregation using inverted indexes"),3,"ES uses inverted indexes for fast text search. Great for log analytics (ELK) and fuzzy matching."),
        quiz("es-2","What is an inverted index?","hard",("elasticsearch",),("A hash table","A B-tree","A data structure mapping each unique term to the list of documents containing it","A sorted array"),2,"Inverted index: term → [doc1, doc5, doc42]. O(1) lookup of which documents contain a search term."),
        quiz("es-3","How does Elasticsearch shard data?","hard",("elasticsearch",),("By time only","Single node only","No sharding","Each index is split into primary shards distributed across nodes; each shard is a self-contained Lucene index"),3,"Default: 1 primary shard per index. Shards enable horizontal scaling. Replica shards add fault tolerance."),
        quiz("es-4","What is the difference between a primary and replica shard?","medium",("elasticsearch",),("Primary handles writes; replicas serve reads and provide failover if primary fails","Replica handles writes","Same thing","Primary is a backup"),0,"Replicas: read scaling + fault tolerance. A replica can be promoted to primary on node failure."),
        quiz("es-5","What is TF-IDF in Elasticsearch?","hard",("elasticsearch",),("A database index","Term Frequency × Inverse Document Frequency — a relevance scoring formula for full-text search","A sharding strategy","A caching algorithm"),1,"TF-IDF: rare terms matching a document score higher. ES now uses BM25 (improved TF-IDF) by default."),
        quiz("es-6","What is BM25?","hard",("elasticsearch",),("A database version","A caching policy","A shard strategy","Okapi BM25: the default relevance scoring algorithm in ES — improves on TF-IDF with term frequency saturation"),3,"BM25 prevents very high term frequencies from dominating scores. Better than raw TF-IDF."),
        quiz("es-7","What is the ELK stack?","medium",("elasticsearch",),("Elasticsearch (search/analytics) + Logstash (ingestion) + Kibana (visualization)","A caching layer","A database cluster","A CDN"),0,"ELK: the go-to for log aggregation, monitoring, and observability."),
        quiz("es-8","What is a mapping in Elasticsearch?","medium",("elasticsearch",),("A configuration file","A routing table","Schema definition: specifies field types (text, keyword, integer, date) and how they're indexed","A geographic feature"),2,"Mapping controls tokenization (text vs keyword), indexing options, and stored fields."),
        quiz("es-9","What is the difference between text and keyword field types?","hard",("elasticsearch",),("Text is analyzed (tokenized, lowercased) for full-text search; keyword is exact match (no tokenization)","Text is faster","Keyword supports fuzzy","Same thing"),0,"Use text for searchable content. Use keyword for exact matches, sorting, and aggregations."),
        quiz("es-10","What is an analyzer in Elasticsearch?","hard",("elasticsearch",),("A shard strategy","A data type","A monitoring tool","A pipeline of character filters, tokenizer, and token filters that processes text for indexing/search"),3,"Standard analyzer: lowercase + tokenize. Custom analyzers handle stemming, synonyms, stopwords."),
        quiz("es-11","How does Elasticsearch handle near-real-time search?","hard",("elasticsearch",),("Real-time always","After commit only","Documents are searchable after a refresh interval (~1 second) when in-memory buffer is written to a segment","Instant indexing"),2,"Refresh creates a new searchable segment from the in-memory buffer. Default interval: 1 second."),
        quiz("es-12","What is a segment in Elasticsearch?","hard",("elasticsearch",),("A database table","A shard subset","A replica","An immutable Lucene index file; new documents create new segments, which are periodically merged"),3,"Segments are immutable. Deletes create tombstones. Merging compacts segments and removes tombstones."),
        quiz("es-13","What are aggregations in Elasticsearch?","medium",("elasticsearch",),("A caching feature","A replication mode","SQL JOINs","Analytics operations: bucket (group by), metric (avg, sum), and pipeline aggregations on search results"),3,"Aggregations enable dashboard analytics: top terms, date histograms, percentiles, nested buckets."),
        quiz("es-14","What is the document routing in Elasticsearch?","hard",("elasticsearch",),("Load balancing","DNS routing","By default, shard = hash(document_id) % num_primary_shards. Custom routing co-locates related docs","A CDN feature"),2,"Custom routing: all docs for a tenant go to the same shard, enabling efficient single-shard queries."),
        quiz("es-15","What is the difference between Elasticsearch and a relational database?","medium",("elasticsearch",),("ES: denormalized, search-optimized, eventually consistent. RDBMS: normalized, transactional, strongly consistent","ES is a database replacement","No difference","RDBMS supports full-text search"),0,"ES is NOT a primary database. It's a search engine used as a read-optimized projection."),
        quiz("es-16","What is the scroll API in Elasticsearch?","hard",("elasticsearch",),("Pagination","Efficiently retrieves large result sets by keeping a point-in-time snapshot, avoiding deep pagination costs","A caching feature","A write API"),1,"Scroll: for batch processing. Search_after: for live pagination. Both avoid the deep-pagination O(n) problem."),
        quiz("es-17","How does Elasticsearch handle updates?","hard",("elasticsearch",),("Direct modification","In-place updates","Documents are immutable; an update creates a new version and marks the old one as deleted","SQL UPDATE"),2,"Lucene segments are immutable. Updates = delete old + index new. Merging reclaims deleted space."),
        quiz("es-18","What is cross-cluster replication in Elasticsearch?","hard",("elasticsearch",),("Within one cluster","Replicating indices across geographically separate clusters for disaster recovery and local reads","A node type","A shard feature"),1,"CCR: leader cluster → follower cluster. Follower serves local reads. Failover if leader goes down."),
        quiz("es-19","What is the percolate query?","hard",("elasticsearch",),("An aggregation","Reverse search: store queries, then match new documents against stored queries (alerting, notifications)","A filter","A standard search"),1,"Percolate: 'which of my saved searches match this new document?' Used for alerts and saved searches."),
        quiz("es-20","How do you handle Elasticsearch at scale?","hard",("elasticsearch",),("Shard per tenant/time, hot-warm-cold architecture, index lifecycle management, and force-merge old indices","Single large node","No scaling needed","Just add RAM"),0,"ILM: hot (SSD, recent) → warm (HDD, older) → cold (frozen, archive). Auto-manages index lifecycle."),
    ))

def kafka_lesson() -> Lesson:
    return Lesson(id="hld-kafka", number=118, title="Kafka",
        focus=("partitions","consumer groups","offsets","replication","exactly-once","Kafka Streams"),
        overview="Kafka is the backbone of event-driven architecture. Know partitions, consumer groups, and delivery guarantees.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("kafka-1","What makes Kafka different from a traditional queue?","hard",("kafka",),("Kafka is simpler","Kafka is faster","Kafka doesn't order","Kafka is a distributed commit log: retains messages, allows replay, and supports multiple consumer groups"),3,"Unlike RabbitMQ, Kafka retains messages after consumption. Consumers track their offset."),
        quiz("kafka-2","What is a Kafka partition?","hard",("kafka",),("A consumer group","A database shard","A topic","The unit of parallelism — messages are ordered within a partition, distributed across brokers"),3,"Partitions enable horizontal scaling. Ordering guaranteed only within a partition."),
        quiz("kafka-3","What is a consumer group?","medium",("kafka",),("A set of consumers sharing partition ownership — each partition consumed by exactly one member","A group of topics","A broker cluster","A replication mechanism"),0,"10 partitions → max 10 consumers in a group. Adding more consumers than partitions wastes them."),
        quiz("kafka-4","What happens when a consumer falls behind?","hard",("kafka",),("Consumer lag increases; it catches up by reading from disk (retention period protects messages)","Topic paused","Messages deleted","Kafka stops producers"),0,"Monitor consumer lag. If consumer can't keep up, add more consumers (up to partition count)."),
        quiz("kafka-5","What is Kafka's replication model?","hard",("kafka",),("Peer-to-peer","Each partition has a leader and N-1 follower replicas. Writes go to leader; followers replicate asynchronously","No replication","Multi-leader"),1,"ISR (In-Sync Replicas): only replicas that are caught up. Leader election from ISR on failure."),
        quiz("kafka-6","What is the ISR (In-Sync Replica) set?","hard",("kafka",),("The subset of replicas that are fully caught up with the leader — only ISR members can be elected leader","A monitoring metric","All replicas","A consumer group"),0,"min.insync.replicas: minimum ISR size required for acks=all. Prevents data loss on leader failure."),
        quiz("kafka-7","What is acks=all in Kafka?","hard",("kafka",),("Acknowledge to leader only","Acknowledge to one broker","Producer waits for all ISR replicas to acknowledge the write before considering it successful","No acknowledgment"),2,"acks=all: highest durability. acks=1: leader only (risk of loss). acks=0: fire-and-forget (fastest)."),
        quiz("kafka-8","How does Kafka achieve high throughput?","hard",("kafka",),("Single partition","Random writes","In-memory only","Sequential I/O (append-only), batching, compression, zero-copy transfer, and OS page cache"),3,"Kafka writes sequentially to disk (faster than random SSD). Zero-copy: sendfile() syscall."),
        quiz("kafka-9","What is Kafka Connect?","medium",("kafka",),("A client library","A monitoring tool","Framework for streaming data between Kafka and external systems via source/sink connectors","A security module"),2,"Source connectors ingest (DB→Kafka). Sink connectors export (Kafka→ES/S3). No custom code needed."),
        quiz("kafka-10","What is Kafka Streams?","hard",("kafka",),("A monitoring tool","A message format","A broker feature","A client library for building stream processing applications that transform Kafka topics"),3,"Kafka Streams: stateful processing, windowing, joins — runs as a regular Java app, no separate cluster."),
        quiz("kafka-11","What is exactly-once semantics (EOS) in Kafka?","hard",("kafka",),("Only for consumers","Impossible","Same as at-least-once","Idempotent producer + transactional writes + consumer read-committed = end-to-end exactly-once within Kafka"),3,"EOS: producer deduplication (idempotent) + atomic multi-partition writes (transactions) + consumer isolation."),
        quiz("kafka-12","What is a Kafka topic compaction?","hard",("kafka",),("A partition strategy","Compression","Log compaction retains only the latest value for each key, discarding older versions — like a changelog","Deleting old messages"),2,"Compacted topics: keep latest state per key. Used for CDC, configuration, and state snapshots."),
        quiz("kafka-13","How does Kafka handle ordering across partitions?","hard",("kafka",),("Global ordering","It doesn't — ordering is only within a partition. Use a single partition for strict global order (limits throughput)","Timestamp sorting","Automatic reordering"),1,"Design your partition key so related messages go to the same partition for ordering."),
        quiz("kafka-14","What is consumer rebalancing?","hard",("kafka",),("When consumers join/leave a group, partitions are reassigned. Causes a brief processing pause","A topic reset","A broker restart","Data migration"),0,"Rebalancing can cause duplicates (at-least-once). Cooperative rebalancing (incremental) reduces impact."),
        quiz("kafka-15","What is the Schema Registry?","hard",("kafka",),("A monitoring tool","A broker feature","A service storing Avro/Protobuf/JSON schemas for Kafka messages, enabling schema evolution and validation","A database"),2,"Schema Registry ensures producers and consumers agree on message format. Supports backward/forward compatibility."),
        quiz("kafka-16","What is a dead letter topic?","medium",("kafka",),("A deleted topic","A backup topic","An error log","A topic where messages that fail processing are sent for later investigation and reprocessing"),3,"DLT: poison messages go here after max retries. Prevents blocking the main consumer."),
        quiz("kafka-17","What is the difference between Kafka's retention by time vs size?","medium",("kafka",),("Time is always used","Same thing","Size is always used","Time-based: delete messages older than N days. Size-based: delete oldest when topic exceeds N GB"),3,"Configure per topic. Time-based for event streams. Size-based for resource-constrained environments."),
        quiz("kafka-18","What is MirrorMaker 2?","hard",("kafka",),("A schema tool","A monitoring tool","Kafka's built-in cross-cluster replication tool for disaster recovery and multi-datacenter setups","A consumer library"),2,"MM2: replicate topics between clusters. Supports active-active and active-passive topologies."),
        quiz("kafka-19","How do you choose the number of partitions for a topic?","hard",("kafka",),("Based on target throughput: partitions ≥ max(producer throughput / partition throughput, consumer count)","Always 100","Always 1","Based on message size"),0,"More partitions = more parallelism but also more overhead (file handles, memory, rebalancing time)."),
        quiz("kafka-20","What is the Kafka transaction protocol?","hard",("kafka",),("Atomic writes across multiple partitions: all messages in a transaction are committed or aborted together","Same as SQL transactions","A locking mechanism","A replication feature"),0,"Transactions enable exactly-once: produce to multiple topics/partitions atomically. Used with Kafka Streams."),
    ))
